INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", "2023/09/22 14:59:59", 1, 0.0, 1, "2023/06/30 12:00:00", 10001, 1, -470.0, 2002, 2, 1.47, 126401, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", "2023/09/22 14:59:59", 1, 0.0, 2, "2023/06/30 12:00:00", 10002, 2, -470.0, 2002, 1, 2.15, 126401, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", "2023/09/22 14:59:59", 1, 0.0, 1, "2023/06/30 12:00:00", 10003, 2, -470.0, 2002, 2, 0.0, 126501, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", "2023/09/22 14:59:59", 1, 0.0, 2, "2023/06/30 12:00:00", 10004, 1, -470.0, 2002, 1, 0.0, 126501, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("リンド", "2023/12/22 14:59:59", 2, 0.0, 1, "2023/09/15 15:00:00", 10005, 2, -470.0, 2002, 2, 0.0, 127702, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("リンド", "2023/12/22 14:59:59", 2, 0.0, 2, "2023/09/15 15:00:00", 10006, 2, -470.0, 2002, 2, 0.0, 127702, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴルム", "2023/12/22 14:59:59", 2, 0.0, 1, "2023/09/15 15:00:00", 10007, 1, -470.0, 2002, 1, 0.0, 127802, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴルム", "2023/12/22 14:59:59", 2, 0.0, 2, "2023/09/15 15:00:00", 10008, 2, -470.0, 2002, 1, 6.5, 127802, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アネモネ", "2024/03/22 14:59:59", 3, 0.0, 1, "2023/12/15 15:00:00", 10009, 2, -470.0, 2002, 1, 0.0, 129602, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アネモネ", "2024/03/22 14:59:59", 3, 0.0, 2, "2023/12/15 15:00:00", 10010, 2, -470.0, 2002, 1, 0.0, 129602, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ=ネラ", "2024/03/22 14:59:59", 3, 0.0, 1, "2023/12/15 15:00:00", 10011, 1, -470.0, 2002, 1, 0.0, 129701, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ=ネラ", "2024/03/22 14:59:59", 3, 0.0, 2, "2023/12/15 15:00:00", 10012, 2, -470.0, 2002, 1, 6.2, 129701, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カノン", "2024/06/22 14:59:59", 4, 0.0, 1, "2024/03/15 15:00:00", 10013, 3, -470.0, 2002, 5, 3.1, 130301, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カノン", "2024/06/22 14:59:59", 4, 0.0, 2, "2024/03/15 15:00:00", 10014, 3, -470.0, 2002, 2, 6.15, 130301, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ナーナ", "2024/06/22 14:59:59", 4, 0.0, 1, "2024/03/15 15:00:00", 10015, 2, -470.0, 2002, 2, 0.0, 130401, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ナーナ", "2024/06/22 14:59:59", 4, 0.0, 2, "2024/03/15 15:00:00", 10016, 2, -470.0, 2002, 1, 3.35, 130401, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", "2024/09/22 14:59:59", 5, 0.0, 1, "2024/06/15 15:00:00", 10017, 1, -470.0, 2002, 1, 0.0, 130502, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", "2024/09/22 14:59:59", 5, 0.0, 2, "2024/06/15 15:00:00", 10018, 2, -470.0, 2002, 1, 3.18, 130502, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", "2024/09/22 14:59:59", 5, 0.0, 3, "2024/06/15 15:00:00", 10019, 4, -470.0, 2002, 4, 0.0, 130503, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネア", "2024/09/22 14:59:59", 5, 0.0, 1, "2024/06/15 15:00:00", 10020, 1, -470.0, 2002, 2, 4.9, 123301, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネア", "2024/09/22 14:59:59", 5, 0.0, 2, "2024/06/15 15:00:00", 10021, 1, -470.0, 2002, 2, 4.8, 123301, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カリザ", "2024/12/22 14:59:59", 6, 0.0, 1, "2024/09/15 15:00:00", 10022, 3, -470.0, 2002, 1, 4.922, 133301, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カリザ", "2024/12/22 14:59:59", 6, 0.0, 2, "2024/09/15 15:00:00", 10023, 3, -470.0, 2002, 5, 9.638, 133301, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ミーア", "2024/12/22 14:59:59", 6, 0.0, 1, "2024/09/15 15:00:00", 10024, 1, -470.0, 2002, 2, 2.88, 133401, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ミーア", "2024/12/22 14:59:59", 6, 0.0, 2, "2024/09/15 15:00:00", 10025, 5, -470.0, 2002, 1, 4.818, 133401, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("グレイス", "2025/03/22 14:59:59", 7, 0.0, 1, "2024/12/15 15:00:00", 10026, 2, -470.0, 2002, 1, 1.78, 133002, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("グレイス", "2025/03/22 14:59:59", 7, 0.0, 2, "2024/12/15 15:00:00", 10027, 1, -470.0, 2002, 7, 6.15, 133002, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴァイオレット", "2025/03/22 14:59:59", 7, 0.0, 1, "2024/12/15 15:00:00", 10028, 6, -470.0, 2002, 2, 4.28, 133102, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴァイオレット", "2025/03/22 14:59:59", 7, 0.0, 2, "2024/12/15 15:00:00", 10029, 1, -470.0, 2002, 1, 0.0, 133102, "じめじめした商品は\nございませんので\n安心してお買い求め下さい");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ルルィ", "2025/06/23 14:59:59", 8, 0.0, 1, "2025/03/15 15:00:00", 10030, 2, -470.0, 2002, 1, 5.53, 136902, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ルルィ", "2025/06/23 14:59:59", 8, 0.0, 2, "2025/03/15 15:00:00", 10031, 9, -470.0, 2002, 7, 6.05, 136902, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("デュラン", "2025/06/23 14:59:59", 8, 0.0, 1, "2025/03/15 15:00:00", 10032, 2, -470.0, 2002, 1, 0.0, 137001, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("デュラン", "2025/06/23 14:59:59", 8, 0.0, 2, "2025/03/15 15:00:00", 10033, 2, -470.0, 2002, 1, 0.0, 137001, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("サツキ", "2025/09/23 14:59:59", 9, 0.0, 1, "2025/06/16 15:00:00", 10034, 2, -470.0, 2002, 2, 0.0, 135902, "おう\n好きなもん持ってきな");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("サツキ", "2025/09/23 14:59:59", 9, 0.0, 2, "2025/06/16 15:00:00", 10035, 1, -470.0, 2002, 6, 4.935, 135902, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ユキノ", "2025/09/23 14:59:59", 9, 0.0, 1, "2025/06/16 15:00:00", 10036, 2, -470.0, 2002, 5, 7.441, 135802, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ユキノ", "2025/09/23 14:59:59", 9, 0.0, 2, "2025/06/16 15:00:00", 10037, 7, -470.0, 2002, 7, 0.0, 135802, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クルル", "2025/12/22 14:59:59", 10, 0.0, 1, "2025/09/16 15:00:00", 10038, 2, -470.0, 2002, 2, 2.295, 130901, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クルル", "2025/12/22 14:59:59", 10, 0.0, 2, "2025/09/16 15:00:00", 10039, 1, -470.0, 2002, 6, 6.281, 130901, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴォルガーノ", "2025/12/22 14:59:59", 10, 0.0, 1, "2025/09/16 15:00:00", 10040, 2, -470.0, 2002, 1, 5.549, 137701, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴォルガーノ", "2025/12/22 14:59:59", 10, 0.0, 2, "2025/09/16 15:00:00", 10041, 3, -470.0, 2002, 6, 2.64, 137701, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", "2026/03/23 11:59:59", 11, 0.0, 1, "2025/12/15 15:00:00", 10042, 7, -470.0, 2002, 4, 7.642, 132801, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", "2026/03/23 11:59:59", 11, 0.0, 2, "2025/12/15 15:00:00", 10043, 1, -470.0, 2002, 1, 0.0, 132802, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", "2026/03/23 11:59:59", 11, 0.0, 1, "2025/12/15 15:00:00", 10044, 1, -470.0, 2002, 1, 0.0, 134502, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", "2026/03/23 11:59:59", 11, 0.0, 2, "2025/12/15 15:00:00", 10045, 2, -470.0, 2002, 1, 3.72, 134501, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ＝ネラ", "2026/06/22 11:59:59", 12, 0.0, 1, "2026/03/16 12:00:00", 10046, 2, -470.0, 2002, 1, 4.991, 138201, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ＝ネラ", "2026/06/22 11:59:59", 12, 0.0, 2, "2026/03/16 12:00:00", 10047, 1, -470.0, 2002, 4, 3.877, 138201, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アラクネ", "2026/06/22 11:59:59", 12, 0.0, 1, "2026/03/16 12:00:00", 10048, 4, -470.0, 2002, 6, 1.71, 136001, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アラクネ", "2026/06/22 11:59:59", 12, 0.0, 2, "2026/03/16 12:00:00", 10049, 5, -470.0, 2002, 2, 5.32, 136001, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…");
